using namespace std;

int main() {
    int N;
    while (cin >> N && N != 0) {
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                cout << (1 << (i + j)) << " ";
            }
            cout << endl;
        }
        cout << endl;
    }
    return 0;
